+/// Time a closure and return duration in milliseconds.
+fn time_ms<F: FnMut()>(mut f: F, iterations: u32) -> u64 {
+    let start = Instant::now();
+    for _ in 0..iterations {
+        f();
+    }
+    start.elapsed().as_millis() as u64
+}
