+        let report_path = format!("{artifacts_dir}/perf_report.json");
+        if let Err(e) = fs::write(&report_path, report.to_json()) {
+            eprintln!("Warning: Failed to save perf report: {e}");
+        }
+    }
+
+    // Fail on regressions
+    assert!(
+        report.all_passed,
+        "Performance regressions detected!\n{}",
+        report.to_summary()
+    );
+}
